    assert categorize(30) not in {'pass', 'excellent'}

def test_truthiness_string_always_non_empty():
    assert categorize(50)        # non-empty string is truthy
    assert categorize(100)

def test_boundaries():
    assert categorize(90) == 'excellent'
    assert categorize(89) == 'pass'
